    std::uint64_t aNonceWordF = TwistMix64::DiffuseB(pNonce * 0xD0A64548D3604A87ULL + 0xEA5ACAF0B9E5570FULL);
    std::uint64_t aNonceWordG = TwistMix64::DiffuseC(pNonce * 0xB80F9CB6EC4CE573ULL + 0xCABD0DC2365CE418ULL);
    std::uint64_t aNonceWordH = TwistMix64::DiffuseC(pNonce * 0xFAAD3EBA6CFC37FBULL + 0xCCF45C8577A31671ULL);
    std::uint64_t aNonceWordI = TwistMix64::DiffuseC(pNonce * 0xD24F60C32ECA4359ULL + 0x8B2DA60D0C64668DULL);
    std::uint64_t aNonceWordJ = TwistMix64::DiffuseC(pNonce * 0xEFBACFED1C6DD44BULL + 0x84FEE8F4EB9EF122ULL);
    std::uint64_t aNonceWordK = TwistMix64::DiffuseB(pNonce * 0xD3E6F832E1FF0BFBULL + 0xACADC9BD266E72BCULL);
    std::uint64_t aNonceWordL = TwistMix64::DiffuseA(pNonce * 0xAC049A972C1F0AC5ULL + 0xA0C4707715C13227ULL);
    std::uint64_t aNonceWordM = TwistMix64::DiffuseB(pNonce * 0xD37AF19F5921C395ULL + 0xD7CE11243A305EEBULL);
    std::uint64_t aNonceWordN = TwistMix64::DiffuseA(pNonce * 0xEF0FD7902B7D36C9ULL + 0xE6D0C73AF02E4BC9ULL);
    std::uint64_t aNonceWordO = TwistMix64::DiffuseB(pNonce * 0x8BBE2F4FA7F485EBULL + 0x82BF8B742EBB29B7ULL);
    std::uint64_t aNonceWordP = TwistMix64::DiffuseC(pNonce * 0x826DB07C794F693DULL + 0xCA537801F48ACACCULL);
