            aOrbiterB = (aOrbiterB + aOrbiterK) + 10791685255163491084U;
            aOrbiterF = (aOrbiterF ^ aOrbiterB) ^ 15492050077755123060U;
            aOrbiterF = RotL64((aOrbiterF * 10175527862179178541U), 23U);
            //
            aOrbiterI = ((aOrbiterI + aOrbiterG) + 16631227414994310444U) + aOrbiterUpdateSaltA[(((31U - aIndex) + 18U)) & S_SALT1];
            aOrbiterK = (aOrbiterK ^ aOrbiterI) ^ 4708116826773302214U;
            aOrbiterK = RotL64((aOrbiterK * 16655097431826971921U), 47U);
            //
            aOrbiterK = (aOrbiterK + aOrbiterH) + 12006185813561663290U;
            aOrbiterE = ((aOrbiterE ^ aOrbiterK) ^ 17520509695271967224U) ^ aNonceWordE;
            aOrbiterE = RotL64((aOrbiterE * 12344002726095396745U), 37U);
            //
            aOrbiterH = (aOrbiterH + aOrbiterD) + 16898733045057935821U;
            aOrbiterJ = (aOrbiterJ ^ aOrbiterH) ^ 12957052172565598744U;
            aOrbiterJ = RotL64((aOrbiterJ * 6454409881502257811U), 11U);
            //
            aOrbiterC = (aOrbiterC + aOrbiterI) + 10362617838654613975U;
            aOrbiterB = (aOrbiterB ^ aOrbiterC) ^ 8761867193243071663U;
            aOrbiterB = RotL64((aOrbiterB * 12457021905608053949U), 35U);
            //
            aOrbiterJ = (aOrbiterJ + aOrbiterC) + 6235691986896135701U;
            aOrbiterA = ((aOrbiterA ^ aOrbiterJ) ^ 6472262809958246634U) ^ aNonceWordK;
            aOrbiterA = RotL64((aOrbiterA * 1429245009334008883U), 29U);
            //
            aOrbiterA = ((aOrbiterA + aOrbiterB) + 4439618761664071669U) + aNonceWordL;
            aOrbiterD = (aOrbiterD ^ aOrbiterA) ^ 6069888131423338128U;
            aOrbiterD = RotL64((aOrbiterD * 15640656271352689927U), 41U);
            //
            aOrbiterD = ((aOrbiterD + aOrbiterF) + 12890282400039900492U) + aOrbiterUpdateSaltD[(((31U - aIndex) + 26U)) & S_SALT1];
            aOrbiterC = (aOrbiterC ^ aOrbiterD) ^ 5578461609437762611U;
