            //
            aOrbiterF = (aOrbiterF + aOrbiterE) + 7184387364504102580U;
            aOrbiterI = ((aOrbiterI ^ aOrbiterF) ^ 712188107863756776U) ^ aOrbiterUpdateSaltF[((aIndex + 20U)) & S_SALT1];
            aOrbiterI = RotL64((aOrbiterI * 3087057716874966297U), 43U);
            //
            aIngress = aOrbiterF ^ RotL64(aOrbiterD, 42U);
