            aIngress = aIngress + (aOrbiterH ^ RotL64(aOrbiterJ, 13U));
            aIngress = aIngress + RotL64(aOrbiterB, 37U);
            aIngress = TwistMix64::DiffuseC((aIngress + aScatter));
            //
            aWandererI = aWandererI + ((((RotL64(aCross, 39U) + RotL64(aOrbiterK, 54U)) + aOrbiterE) + aNonceWordC) + aWandererUpdateSaltE[(((31U - aIndex) + 17U)) & S_SALT1]);
            aWandererB = aWandererB ^ ((RotL64(aPrevious, 46U) + RotL64(aOrbiterB, 39U)) + aOrbiterA);
            aWandererG = aWandererG + ((RotL64(aScatter, 3U) + aOrbiterI) + RotL64(aOrbiterH, 41U));
