            aOrbiterB = ((aOrbiterB + aOrbiterJ) + 2894238117977881020U) + aOrbiterUpdateSaltA[((aIndex + 11U)) & S_SALT1];
            aOrbiterI = ((aOrbiterI ^ aOrbiterB) ^ 13908684216963108338U) ^ aNonceWordH;
